import React, { useState, useEffect } from 'react';
import axios from 'axios';

function App() {
  const [user, setUser] = useState(null);
  const [transactions, setTransactions] = useState([]);
  const [amount, setAmount] = useState(0);
  const [type, setType] = useState('deposit');

  useEffect(() => {
    if (user) {
      axios.get(`/api/transactions/${user._id}`).then(res => {
        setTransactions(res.data);
      });
    }
  }, [user]);

  const handleTransaction = async () => {
    await axios.post('/api/transactions', {
      userId: user._id,
      amount: Number(amount),
      type
    });
    const res = await axios.get(`/api/transactions/${user._id}`);
    setTransactions(res.data);
  };

  return (
    <div className="App">
      {!user ? (
        <button onClick={() => setUser({ _id: 'mockUserId' })}>Login</button>
      ) : (
        <div>
          <h2>Welcome {user.name}</h2>
          <h3>Balance: ${user.balance}</h3>
          <input
            type="number"
            value={amount}
            onChange={(e) => setAmount(e.target.value)}
            placeholder="Amount"
          />
          <select value={type} onChange={(e) => setType(e.target.value)}>
            <option value="deposit">Deposit</option>
            <option value="withdrawal">Withdrawal</option>
          </select>
          <button onClick={handleTransaction}>Submit</button>

          <h4>Transaction History</h4>
          <ul>
            {transactions.map((t, i) => (
              <li key={i}>{t.type} - ${t.amount} on {new Date(t.date).toLocaleDateString()}</li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
}

export default App;
